function subsets(data) {
    const text = (data || '').trim();
    if (!text) return '[[]]';

    const nums = text.split(/\s+/).map(Number).filter((x) => !Number.isNaN(x));
    const n = nums.length;
    if (n === 0) return '[[]]';

    const out = [];
    for (let mask = 0; mask < (1 << n); mask++) {
        const subset = [];
        for (let i = 0; i < n; i++) {
            if (mask & (1 << i)) subset.push(nums[i]);
        }
        out.push(subset.join(' '));
    }
    return out.join('\n');
}

