import java.util.List;
class Solution {
    public List<List<Integer>> subsets(int[] data) {
        List<List<Integer>> result = new ArrayList<>();
        int n = data.length;
        int totalSubsets = 1 << n; // 2^n
        for (int i = 0; i < totalSubsets; i++) {
            List<Integer> subset = new ArrayList<>();
            for (int j = 0; j < n; j++) {
                if ((i & (1 << j)) != 0) {
                    subset.add(data[j]);
                }
            }
            result.add(subset);
        }
        return result;
    }
}

