type List[T any] []T

func subsets(data []int) List[List[int]] {
    var result List[List[int]]
    var backtrack func(start int, current List[int])
    backtrack = func(start int, current List[int]) {
        result = append(result, append(List[int]{}, current...))
        for i := start; i < len(data); i++ {
            current = append(current, data[i])
            backtrack(i+1, current)
            current = current[:len(current)-1]
        }
    }
    backtrack(0, List[int]{})
    return result
}

